type Result<T> =
  | { ok: true; value: T }
  | { ok: false; error: string };

export function parsePort(input: string): Result<number> {
  const port = Number(input);
  if (!Number.isInteger(port) || port <= 0) {
    return { ok: false, error: `invalid port: ${input}` };
  }
  return { ok: true, value: port };
}

